CREATE TABLE IF NOT EXISTS `document_templates` (
  `id` int NOT NULL AUTO_INCREMENT,
  `companyId` int NOT NULL,
  `tipo` enum('advertencia_verbal','advertencia_escrita','suspensao','justa_causa','outros') NOT NULL,
  `titulo` varchar(255) NOT NULL,
  `conteudo` text NOT NULL,
  `ativo` tinyint NOT NULL DEFAULT 1,
  `criadoPor` varchar(255),
  `atualizadoPor` varchar(255),
  `createdAt` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP,
  `updatedAt` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,
  PRIMARY KEY (`id`),
  INDEX `doc_templates_company_tipo` (`companyId`, `tipo`)
);

ALTER TABLE `warnings` ADD COLUMN IF NOT EXISTS `sequencia` int DEFAULT 1;
ALTER TABLE `warnings` ADD COLUMN IF NOT EXISTS `aplicadoPor` varchar(255);
ALTER TABLE `warnings` ADD COLUMN IF NOT EXISTS `diasSuspensao` int;
ALTER TABLE `warnings` ADD COLUMN IF NOT EXISTS `origemModulo` varchar(50);
ALTER TABLE `warnings` ADD COLUMN IF NOT EXISTS `origemId` int;
ALTER TABLE `warnings` MODIFY COLUMN `tipoAdvertencia` enum('Verbal','Escrita','Suspensao','JustaCausa','OSS') NOT NULL;

